const jobs = $input.all().map((i) => i.json || {});
if (jobs.length === 0) {
  throw new Error('[Create Governance PR (GitHub API)] nenhum job recebido.');
}

const toStr = (v) => String(v ?? '').trim();
const toArr = (v) => Array.isArray(v) ? v : [];
const uniq = (arr) => [...new Set(toArr(arr).map((x) => toStr(x)).filter(Boolean))];

const sanitize = (v) => toStr(v).replace(/[^a-zA-Z0-9._-]/g, '-');
const encodePath = (p) => toStr(p).split('/').map(encodeURIComponent).join('/');

const parseSnippet = (snippet, idx) => {
  const raw = toStr(snippet).replace(/\r\n/g, '\n');
  if (!raw) throw new Error('[Create Governance PR (GitHub API)] snippet vazio em index ' + idx);

  const lines = raw.split('\n');
  const first = toStr(lines[0]);
  const match = first.match(/^\/\/\s*file:\s*(.+)$/i);
  if (!match) {
    throw new Error('[Create Governance PR (GitHub API)] snippet sem header // file: <path> em index ' + idx);
  }

  const filePath = toStr(match[1]).replace(/^['\"]|['\"]$/g, '');
  if (!filePath || filePath.includes('..') || filePath.startsWith('/')) {
    throw new Error('[Create Governance PR (GitHub API)] caminho de arquivo invalido: ' + filePath);
  }

  const content = lines.slice(1).join('\n').replace(/^\n+/, '');
  if (!toStr(content)) {
    throw new Error('[Create Governance PR (GitHub API)] conteudo vazio para arquivo: ' + filePath);
  }

  return { filePath, content };
};

const parseBody = (body) => {
  if (body === undefined || body === null) return null;
  if (typeof body === 'object') return body;
  const text = String(body);
  try {
    return JSON.parse(text);
  } catch (_e) {
    return null;
  }
};

const asText = (value) => {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string') return value;
  try {
    return JSON.stringify(value);
  } catch (_e) {
    return String(value);
  }
};

const inferStatus = (e, fallbackText) => {
  const direct = Number(
    e?.statusCode ||
    e?.status ||
    e?.httpCode ||
    e?.response?.statusCode ||
    e?.response?.status ||
    0
  );
  if (Number.isFinite(direct) && direct > 0) return direct;

  const text = asText(fallbackText || e?.message || '');
  const m = text.match(/status code\s*(\d{3})/i) || text.match(/\b(\d{3})\b/);
  if (m) {
    const n = Number(m[1]);
    if (Number.isFinite(n)) return n;
  }
  return 0;
};

const gh = async ({ method, url, token, body }) => {
  try {
    const resp = await this.helpers.httpRequest({
      method,
      url,
      headers: {
        Authorization: 'Bearer ' + token,
        Accept: 'application/vnd.github+json',
        'X-GitHub-Api-Version': '2022-11-28',
      },
      body,
      json: true,
    });

    return {
      ok: true,
      status: 200,
      text: asText(resp),
      json: resp,
    };
  } catch (e) {
    const bodyData = e?.response?.body ?? e?.message ?? e;
    const status = inferStatus(e, bodyData);
    return {
      ok: false,
      status,
      text: asText(bodyData),
      json: parseBody(bodyData),
    };
  }
};

const buildChangeMappings = (changesInRepo, filesTouched) => {
  const rows = [];

  for (const item of toArr(changesInRepo)) {
    const summary = toStr(item?.change_summary || item?.summary || item?.descricao || item?.description) || 'Mudanca tecnica sem descricao';
    const snippets = toArr(item?.code_changes || item?.snippets);
    const files = [];

    for (let i = 0; i < snippets.length; i += 1) {
      try {
        const parsed = parseSnippet(snippets[i], i);
        if (parsed?.filePath) files.push(parsed.filePath);
      } catch (_e) {
        // snippet invalido ja foi tratado no fluxo principal
      }
    }

    rows.push({
      summary,
      files: uniq(files),
    });
  }

  if (rows.length === 0) {
    rows.push({
      summary: 'Mudancas aplicadas via code_changes',
      files: uniq(filesTouched),
    });
  }

  return rows;
};

const buildPrBody = ({ analysisId, repo, baseRef, branch, filesTouched, mappings }) => {
  const summaries = uniq(mappings.map((m) => m.summary));
  const lines = [
    'PR automatica criada pelo fluxo n8n.',
    '',
    '- analysis_id: ' + analysisId,
    '- repo: ' + repo,
    '- base: ' + baseRef,
    '- branch: ' + branch,
    '- arquivos: ' + filesTouched.length,
    '',
    '## Mudancas em linguagem natural',
  ];

  for (const summary of summaries) {
    lines.push('- ' + summary);
  }

  lines.push('');
  lines.push('## Relacao com changes_in_repo');
  lines.push('| Change (changes_in_repo) | Arquivos alterados |');
  lines.push('| --- | --- |');

  for (const row of mappings) {
    const filesInline = row.files.length > 0 ? row.files.join('<br>') : '(sem mapeamento)';
    lines.push('| ' + row.summary + ' | ' + filesInline + ' |');
  }

  lines.push('');
  lines.push('## Arquivos alterados (detalhe)');
  for (const filePath of uniq(filesTouched)) {
    lines.push('- ' + filePath);
  }

  return lines.join('\n');
};

const out = [];

for (const job of jobs) {
  const owner = toStr(job.owner);
  const repo = toStr(job.target_repo);
  const token = toStr(job.github_token);
  const baseRef = toStr(job.base_ref || 'main') || 'main';
  const repoKey = sanitize(job.repo_key || repo);
  const analysisId = sanitize(job.impact_analysis_id || 'na');
  const runId = sanitize(job.run_id || Date.now());

  if (!owner || !repo || !token) {
    throw new Error('[Create Governance PR (GitHub API)] job invalido: owner/repo/token ausentes');
  }

  const parsedSnippets = toArr(job.snippets).map((s, idx) => parseSnippet(s, idx));
  if (parsedSnippets.length === 0) {
    throw new Error('[Create Governance PR (GitHub API)] sem snippets para ' + repo);
  }

  const branch = 'codex/governance-' + analysisId + '-' + repoKey + '-' + runId.slice(-20);
  const prTitle = 'Governance: Impact Analysis ' + analysisId + ' (' + repoKey + ')';

  const baseRefResp = await gh({
    method: 'GET',
    url: 'https://api.github.com/repos/' + owner + '/' + repo + '/git/ref/heads/' + encodeURIComponent(baseRef),
    token,
  });
  if (!baseRefResp.ok || !baseRefResp.json || !baseRefResp.json.object || !baseRefResp.json.object.sha) {
    throw new Error('[Create Governance PR (GitHub API)] falha ao ler base ref ' + baseRef + ' em ' + repo + ': ' + baseRefResp.status + ' ' + (baseRefResp.text || '').slice(0, 300));
  }
  const baseSha = toStr(baseRefResp.json.object.sha);

  const createBranchResp = await gh({
    method: 'POST',
    url: 'https://api.github.com/repos/' + owner + '/' + repo + '/git/refs',
    token,
    body: { ref: 'refs/heads/' + branch, sha: baseSha },
  });

  if (!createBranchResp.ok && createBranchResp.status !== 422) {
    throw new Error('[Create Governance PR (GitHub API)] falha ao criar branch ' + branch + ' em ' + repo + ': ' + createBranchResp.status + ' ' + (createBranchResp.text || '').slice(0, 300));
  }

  const filesTouched = [];

  for (const s of parsedSnippets) {
    const contentApiUrl = 'https://api.github.com/repos/' + owner + '/' + repo + '/contents/' + encodePath(s.filePath);
    const createBody = {
      message: 'chore(governance): apply code_changes for analysis ' + analysisId,
      content: Buffer.from(s.content, 'utf8').toString('base64'),
      branch,
    };

    let putResp = await gh({
      method: 'PUT',
      url: contentApiUrl,
      token,
      body: createBody,
    });

    if (!putResp.ok && putResp.status === 422) {
      const getResp = await gh({
        method: 'GET',
        url: contentApiUrl + '?ref=' + encodeURIComponent(branch),
        token,
      });

      if (!getResp.ok || !getResp.json || !getResp.json.sha) {
        throw new Error('[Create Governance PR (GitHub API)] falha ao buscar sha para update do arquivo ' + s.filePath + ' em ' + repo + ': ' + getResp.status + ' ' + (getResp.text || '').slice(0, 300));
      }

      const updateBody = {
        ...createBody,
        sha: toStr(getResp.json.sha),
      };

      putResp = await gh({
        method: 'PUT',
        url: contentApiUrl,
        token,
        body: updateBody,
      });
    }

    if (!putResp.ok) {
      throw new Error('[Create Governance PR (GitHub API)] falha ao gravar arquivo ' + s.filePath + ' em ' + repo + ': ' + putResp.status + ' ' + (putResp.text || '').slice(0, 300));
    }

    filesTouched.push(s.filePath);
  }

  const mappings = buildChangeMappings(job.changes_in_repo, filesTouched);
  const prBody = buildPrBody({ analysisId, repo, baseRef, branch, filesTouched, mappings });

  const findPrResp = await gh({
    method: 'GET',
    url: 'https://api.github.com/repos/' + owner + '/' + repo + '/pulls?state=open&head=' + encodeURIComponent(owner + ':' + branch),
    token,
  });

  let prUrl = '';
  let prNumber = null;

  if (findPrResp.ok && Array.isArray(findPrResp.json) && findPrResp.json.length > 0) {
    const currentPr = findPrResp.json[0] || {};
    prNumber = Number(currentPr.number || 0) || null;
    prUrl = toStr(currentPr.html_url);

    if (prNumber) {
      if (currentPr.draft === true) {
        const readyResp = await gh({
          method: 'POST',
          url: 'https://api.github.com/repos/' + owner + '/' + repo + '/pulls/' + prNumber + '/ready_for_review',
          token,
          body: {},
        });
        if (!readyResp.ok && readyResp.status !== 422) {
          throw new Error('[Create Governance PR (GitHub API)] falha ao marcar PR ready for review em ' + repo + ': ' + readyResp.status + ' ' + (readyResp.text || '').slice(0, 300));
        }
      }

      const updatePrResp = await gh({
        method: 'PATCH',
        url: 'https://api.github.com/repos/' + owner + '/' + repo + '/pulls/' + prNumber,
        token,
        body: {
          title: prTitle,
          body: prBody,
        },
      });
      if (!updatePrResp.ok) {
        throw new Error('[Create Governance PR (GitHub API)] falha ao atualizar PR existente em ' + repo + ': ' + updatePrResp.status + ' ' + (updatePrResp.text || '').slice(0, 300));
      }

      prUrl = toStr(updatePrResp.json?.html_url || prUrl);
    }
  } else {
    const createPrResp = await gh({
      method: 'POST',
      url: 'https://api.github.com/repos/' + owner + '/' + repo + '/pulls',
      token,
      body: {
        title: prTitle,
        head: branch,
        base: baseRef,
        draft: false,
        body: prBody,
      },
    });

    if (!createPrResp.ok) {
      throw new Error('[Create Governance PR (GitHub API)] falha ao criar PR em ' + repo + ': ' + createPrResp.status + ' ' + (createPrResp.text || '').slice(0, 400));
    }

    prUrl = toStr(createPrResp.json && createPrResp.json.html_url);
    prNumber = Number((createPrResp.json && createPrResp.json.number) || 0) || null;
  }

  out.push({
    json: {
      status: 'implemented',
      owner,
      repo,
      base_ref: baseRef,
      branch,
      pr_url: prUrl,
      pr_number: prNumber,
      files_touched: uniq(filesTouched),
      files_count: uniq(filesTouched).length,
      snippets_count: parsedSnippets.length,
      changes_in_repo_count: toArr(job.changes_in_repo).length,
      impact_analysis_id: analysisId,
    }
  });
}

return out;

const rows = $input.all().map((i) => i.json || {});

const toStr = (v) => String(v ?? '').trim();
const escapeHtml = (s) => toStr(s)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const prs = rows
  .map((r, idx) => ({
    index: idx + 1,
    repo: toStr(r.repo || r.target_repo || 'repo'),
    branch: toStr(r.branch || ''),
    url: toStr(r.pr_url || ''),
    files_count: Number.isFinite(Number(r.files_count)) ? Number(r.files_count) : 0,
    snippets_count: Number.isFinite(Number(r.snippets_count)) ? Number(r.snippets_count) : 0,
  }))
  .filter((r) => r.url);

if (prs.length === 0) {
  throw new Error('[Render PR Links HTML] nenhum pr_url recebido de Create Governance PR (GitHub API).');
}

const listHtml = prs.map((pr) => {
  return [
    '<li style="margin: 0 0 14px;">',
    `<a href="${escapeHtml(pr.url)}" target="_blank" rel="noopener noreferrer" style="font-size:16px;">#${pr.index} ${escapeHtml(pr.repo)}</a>`,
    `<div style="color:#444; font-size:13px; margin-top:4px;">branch: <code>${escapeHtml(pr.branch)}</code> | files: ${pr.files_count} | snippets: ${pr.snippets_count}</div>`,
    '</li>'
  ].join('');
}).join('');

const html = [
  '<!doctype html>',
  '<html lang="pt-BR">',
  '<head>',
  '  <meta charset="utf-8" />',
  '  <meta name="viewport" content="width=device-width, initial-scale=1" />',
  '  <title>Governance PRs</title>',
  '</head>',
  '<body style="font-family: -apple-system, BlinkMacSystemFont, Segoe UI, Roboto, sans-serif; margin: 24px;">',
  '  <h1 style="margin:0 0 8px;">PRs geradas</h1>',
  `  <p style="margin:0 0 20px; color:#444;">Total: <strong>${prs.length}</strong></p>`,
  `  <ul style="padding-left: 20px;">${listHtml}</ul>`,
  '</body>',
  '</html>'
].join('\n');

return [{
  json: {
    status: 'success',
    pr_count: prs.length,
    prs,
    html,
    content_type: 'text/html; charset=utf-8'
  }
}];
